// The datetime to check
const targetDateTime = $('Webhook').first().json.body.args.date;

// The data object
const data = $input.first().json;

// Helper function to format time while respecting the original timezone
function formatTime(dateString) {
  const date = new Date(dateString);
  const options = {
    hour: 'numeric',
    minute: 'numeric',
    hour12: true,
    timeZone: 'America/Los_Angeles' // Use a specific timezone if needed
  };
  return date.toLocaleTimeString('en-US', options);
}

// Helper function to get day of the week
function getDayOfWeek(dateString) {
  const date = new Date(dateString);
  const options = { weekday: 'long', timeZone: 'America/Los_Angeles' }; // Use specific timezone if needed
  return date.toLocaleDateString('en-US', options);
}

// Flatten the slots into a single array
let allSlots = [];
for (const [date, details] of Object.entries(data)) {
  if (details.slots) {
    allSlots = allSlots.concat(details.slots);
  }
}

// Check if the target datetime is present
if (allSlots.includes(targetDateTime)) {
  const day = getDayOfWeek(targetDateTime);
  const time = formatTime(targetDateTime);
  return { result: `${day} at ${time} is available.` };
} else {
  // Convert datetimes to Date objects with original strings for time zone preservation
  const slotsWithOriginal = allSlots.map(slot => ({ date: new Date(slot), original: slot }));
  const targetDate = new Date(targetDateTime);

  // Sort slots by date
  const sortedSlots = slotsWithOriginal.sort((a, b) => a.date - b.date);

  // Find the two closest slots
  let closestBefore = null;
  let closestAfter = null;
  let secondClosestAfter = null;

  for (let i = 0; i < sortedSlots.length; i++) {
    if (sortedSlots[i].date < targetDate) {
      closestBefore = sortedSlots[i].original;
    } else if (!closestAfter) {
      closestAfter = sortedSlots[i].original;
      if (i + 1 < sortedSlots.length) {
        secondClosestAfter = sortedSlots[i + 1].original;
      }
      break;
    }
  }

  // If no closestBefore, return two closest after
  if (!closestBefore) {
    closestBefore = closestAfter;
    closestAfter = secondClosestAfter;
  }

  return { closestBefore, closestAfter };
}

// Get current year from system date
const currentYear = new Date().getFullYear();
for (const item of $input.all()) {
  const appointmentDate = item.json.body?.args?.appointment_datetime;
  if (appointmentDate) {
    const oldDate = new Date(appointmentDate);
    oldDate.setFullYear(currentYear);
    // Set the updated date back in the same nested structure
    item.json.body.args.appointment_datetime = oldDate.toISOString();
  }
}
return $input.all();
